import React from "react";
import { BrowserRouter as Router, Route, Routes } from "react-router-dom"; // Update imports
import Navbar from "./components/Navbar";
import Home from "./components/Home";
import About from "./components/About";
import PracticeAreas from "./components/PracticeAreas";
import Professionals from "./components/Professionals";
import News from "./components/News";
import Gallery from "./components/Gallery";
import Contact from "./components/Contact";
import NewsDetail from "./components/NewsDetail"; // Import NewsDetail component
import "./styles.css"; // Import global styles

function App() {
  return (
    <Router>
      <div>
        <Navbar />
        <Routes> {/* Replace Switch with Routes */}
          <Route path="/" element={<Home />} />
          <Route path="/about" element={<About />} />
          <Route path="/practice-areas" element={<PracticeAreas />} />
          <Route path="/professionals" element={<Professionals />} />
          <Route path="/news" element={<News />} />
          <Route path="/news/:id" element={<NewsDetail />} /> {/* Updated route syntax */}
          <Route path="/gallery" element={<Gallery />} />
          <Route path="/contact" element={<Contact />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
